+async fn handle_import(cmd: ImportCommand) -> CliResult<()> {
+    match cmd {
+        ImportCommand::Chatgpt {
+            path,
+            output_dir,
+            json,
+        } => import_chatgpt_export(&path, output_dir.as_deref(), json).await,
